import sys, json, os, unicodedata

query = sys.argv[1] or os.getenv('mainStr','')
query = unicodedata.normalize('NFC', query.decode('utf-8', 'ignore'))

modsKeys = {
        'alt': {
            'arg': query,
            'subtitle': 'Append extra string before sending',
            'variables': { 'mainStr': query, 'action': 'append' },
        },
        'ctrl': {
            'arg': query,
            'subtitle': 'Prepend extra string before sending',
            'variables': { 'mainStr': query, 'action': 'prepend' },
        },
    }

data = { 'items': [] }

data['items'].append({
    'title': 'Send to Cardhop',
    'arg': query,
    'variables': { 'mainStr': query, 'action': 'send' },
    'mods': modsKeys
})

data['items'].append({
    'title': 'Favorites',
    'subtitle': 'Use the query with an item in the Favorites list',
    'arg': query,
    'variables': { 'mainStr': query, 'action': 'favorites' },
    'mods': modsKeys
})

data['items'].append({
    'title': 'Actions',
    'subtitle': 'Use the query with a Cardhop Action',
    'arg': query,
    'variables': { 'mainStr': query, 'action': 'ch-actions' },
    'mods': modsKeys
})

json.dump(data, sys.stdout)

import sys, json, os, unicodedata

query = sys.argv[1]
query = unicodedata.normalize('NFC', query.decode('utf-8', 'ignore'))
mainStr = os.getenv('mainStr',"")
mainStr = unicodedata.normalize('NFC', mainStr.decode('utf-8', 'ignore'))

if query:
    mainStr = mainStr.replace('{q}', query)

def modsKeys(item):
    return {
        'alt': {
            'arg': item,
            'subtitle': 'Append extra string before sending',
            'variables': { 'mainStr': item, 'action': 'append' },
        },
        'ctrl': {
            'arg': item,
            'subtitle': 'Prepend extra string before sending',
            'variables': { 'mainStr': item, 'action': 'prepend' },
        },
        'cmd': {
            'arg': item,
            'subtitle': 'Use this item with another action',
            'variables': { 'mainStr': item, 'action': 'list' },
        },
    }

data = { 'items': [] }
data['items'].append({
    'title': 'Replace {q} in string',
    'subtitle': mainStr,
    'arg': mainStr,
    'variables': { 'mainStr': mainStr, 'action': 'send' },
    'text' : {
        'copy' : mainStr,
        'largetype' : mainStr
    },
    'mods': modsKeys(mainStr)
})

json.dump(data, sys.stdout)

import sys, json, os, unicodedata

strList = os.getenv("Favorites","").split(";")
mainStr = os.getenv('mainStr',"")
mainStr = unicodedata.normalize('NFC', mainStr.decode('utf-8', 'ignore'))

def modsKeys(item):
    return {
        'alt': {
            'arg': item,
            'subtitle': 'Append extra string before sending',
            'variables': { 'mainStr': item, 'action': 'append' },
        },
        'ctrl': {
            'arg': item,
            'subtitle': 'Prepend extra string before sending',
            'variables': { 'mainStr': item, 'action': 'prepend' },
        },
        'cmd': {
            'arg': item,
            'subtitle': 'Use this item with another send action',
            'variables': { 'mainStr': item, 'action': 'list' },
        },
    }

data = { 'items': [] }
if strList[0] == "":
	data['items'].append({
        'title': "Empty Favorites list",
        'subtitle': "Go into the Workflow's preference to add items",
        'variables': { 'mainStr': item, 'action': '' },
        'mods': modsKeys(item)
    })
else:
    for item in strList:
        item = unicodedata.normalize('NFC', item.decode('utf-8', 'ignore'))
        if mainStr != "":
            item = item.replace('{q}', mainStr)
        data['items'].append({
            'title': item,
            'arg': item,
            'variables': { 'mainStr': item, 'action': 'send' },
            'uid': item,
            'autocomplete': item,
            'text' : {
                'copy' : item,
                'largetype' : item
            },
            'mods': modsKeys(item)
        })

json.dump(data, sys.stdout)

function run(argv) {
	//var query = argv[0];
	var app = Application('Cardhop')
	app.includeStandardAdditions = true

	curApp = Application.currentApplication()
	curApp.includeStandardAdditions = true

	var actionsList = [
		["Call", "dial,call,phone", "Call a contact using your phone. Uses your iPhone through Continuity or Wi-Fi Calling, or a phone paired with your Mac with Bluetooth. You can choose whether you use Continuity and Wi-Fi Calling or Bluetooth in the preferences."],

		["Copy", "copy", "Copy a contact’s information. You can copy specific properties by typing something like “copy Alexis address” or “copy Alexis work email”."],

		["Directions", "map,maps,direction,directions,route", "Compose an email to a contact or group."],

		["FaceTime", "facetime,ft", "Start a FaceTime video call with a contact."],

		["FaceTime Audio", "facetimeaudio,audio,facetime audio,fta", "Start a FaceTime Audio call with a contact."],

		["Large Type", "large,banner,show,big,large type", "Show information about a contact in large type so you can read it from far away. You can show phone numbers and addresses in large type."],

		["Print", "print", "Print mailing labels, envelopes, or a list of information for a contact or group."],

		["Message", "imessage,message,text,txt,im,ping,sms", "Start an iMessage text message with a contact."],

		["Skype", "skype", "Start a Skype call with a contact."],

		["Skype for Business", "skypefb,skypeb,sfb", "Start a Skype for Business call with a contact."],

		["Telegram", "telegram,tg", "Send a Telegram message to a contact."],

		["Twitter", "tweet,twitter", "Send a tweet to a contact."],

		["URL", "website,webpage,url,web", "Open the URL associated with a contact."],

		["VoIP", "voip", "Start a Voice over IP call with a contact. This action sends the phone number to an app that supports callto:// or sip:// URLs."]
	]

	var data = { 'items': [] };
	var actionItem
	for (var i = 0; i < actionsList.length; i++) {
		actionItem = app.localizedString(actionsList[i][1]).split(",")[0] + " " + curApp.systemAttribute("mainStr")
		data.items.push({
			'title': app.localizedString(actionsList[i][0]) + " : " + app.localizedString(actionsList[i][1]).replace(/,/g, ", "), 
			'subtitle': app.localizedString(actionsList[i][2]),
			'arg': actionItem,
			'variables': {'action': 'send' },
			'text' : {
	        	'copy' : 'copy',
	        	'largetype' : app.localizedString(actionsList[i][2])
	    	},
			'mods': {
		        'alt': {
		            'arg': actionItem,
		            'subtitle': 'Append extra string before sending',
		            'variables': { 'mainStr': actionItem, 'action': 'append' },
		        },
		        'ctrl': {
		            'arg': actionItem,
		            'subtitle': 'Prepend extra string before sending',
		            'variables': { 'mainStr': actionItem, 'action': 'prepend' },
		        },
		        'cmd': {
		            'arg': actionItem,
		            'subtitle': 'Use this item with another send action',
		            'variables': { 'mainStr': actionItem, 'action': 'list' },
		        },
		    }
		})
	}
	return JSON.stringify(data);
}

import sys, json, os, unicodedata

query = sys.argv[1]
query = unicodedata.normalize('NFC', query.decode('utf-8', 'ignore'))
mainStr = os.getenv("mainStr","")
mainStr = unicodedata.normalize('NFC', mainStr.decode('utf-8', 'ignore'))
action = os.getenv("action","")
strList = (os.getenv("PrependToSend","") if action == "prepend" else os.getenv("AppendToSend","")).split(";")

def modsKeys(outStr):
    return {
        'alt': {
            'arg': outStr,
            'subtitle': 'Append extra string before sending',
            'variables': { 'mainStr': outStr, 'action': 'append' },
        },
        'ctrl': {
            'arg': outStr,
            'subtitle': 'Prepend extra string before sending',
            'variables': { 'mainStr': outStr, 'action': 'prepend' },
        },
        'cmd': {
            'arg': outStr,
            'subtitle': 'Use this item with another send action',
            'variables': { 'mainStr': outStr, 'action': 'list' },
        },
    }

data = { 'items': [] }

def prependItemToOutput(txt, item):
    outStr = item + " " + mainStr
    data['items'].append({
        'title': txt+item,
        'arg': outStr,
        'variables': { 'mainStr': outStr, 'action': 'send' },
        'uid': item,
        'autocomplete': item,
        'text' : {
            'copy' : outStr,
            'largetype' : outStr
        },
        'mods': modsKeys(outStr)
    })

def appendItemToOutput(txt, item):
    outStr = mainStr + " " + item
    data['items'].append({
        'title': txt+item,
        'arg': outStr,
        'variables': { 'mainStr': outStr, 'action': 'send' },
        'uid': item,
        'autocomplete': item,
        'text' : {
            'copy' : outStr,
            'largetype' : outStr
        },
        'mods': modsKeys(outStr)
    })

addItemToOutput = prependItemToOutput if action == "prepend" else appendItemToOutput

for item in strList:
	if (query and query not in item):
		continue
	addItemToOutput("",item)

if query:
	addItemToOutput('Add: ', query)

json.dump(data, sys.stdout)

